import { useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8000/api";

function ReportFormPage() {
  const navigate = useNavigate();
  const [formState, setFormState] = useState({
    instalacao: "",
    sistema: "",
    equipamento: "",
    data: "",
    gerencia: "",
    numero_ordem: "",
    situacao_identificada: "",
  });
  const [message, setMessage] = useState("");

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormState({ ...formState, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    try {
      await axios.post(`${API_URL}/reports`, formState);
      setMessage("Registro salvo com sucesso.");
    } catch (err) {
      setMessage("Falha ao salvar registro.");
    }
  };

  return (
    <div className="app-shell">
      <header className="app-header">
        <h1>Nova Ordem de Serviço</h1>
      </header>
      <div className="navigation-card">
        <button type="button" className="secondary-button" onClick={() => navigate("/dashboard")}>Dashboard</button>
        <button type="button" className="secondary-button" onClick={() => navigate("/history")}>Histórico</button>
        <button type="button" className="secondary-button" onClick={() => navigate("/executive")}>Executivo</button>
      </div>
      <div className="form-card">
        <form onSubmit={handleSubmit}>
          <div className="form-field">
            <label>Instalação</label>
            <input name="instalacao" value={formState.instalacao} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Sistema</label>
            <input name="sistema" value={formState.sistema} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Equipamento</label>
            <input name="equipamento" value={formState.equipamento} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Data</label>
            <input type="date" name="data" value={formState.data} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Gerência</label>
            <input name="gerencia" value={formState.gerencia} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Número da Ordem</label>
            <input name="numero_ordem" value={formState.numero_ordem} onChange={handleChange} required />
          </div>

          <div className="form-field">
            <label>Situação Identificada</label>
            <textarea name="situacao_identificada" rows={15} value={formState.situacao_identificada} onChange={handleChange} required />
          </div>

          <div className="button-row">
            <button type="submit" className="primary-button">Salvar</button>
            <button type="reset" className="secondary-button">Limpar</button>
          </div>
        </form>
        {message && <div className="form-message">{message}</div>}
      </div>
    </div>
  );
}

export default ReportFormPage;
